### 2. Create `Utilities/RedactingLogger.swift`

A wrapper around `os.Logger` that ensures sensitive data is never logged.

```swift
import os

/// RedactingLogger wraps Apple's os.Logger to ensure sensitive
/// data like stream keys and passwords are never written to logs.
/// 
/// Usage:
///   let log = RedactingLogger(subsystem: "com.port80.app", category: "streaming")
///   log.info("Connected to server")  // Safe - no secrets
///   log.debug("URL: \(url, privacy: .private)")  // Redacted in release
struct RedactingLogger {
    let logger: Logger

    init(subsystem: String = "com.port80.app", category: String) {
        self.logger = Logger(subsystem: subsystem, category: category)
    }

    // Provide convenience methods: debug, info, warning, error, critical
    // Each should use os.Logger with appropriate privacy annotations
    // In debug builds, log more detail
    // In release builds, minimize logging
}
```

